		<view class="header-mario">
			<view class="header-item">
				<text class="label">MARIO</text>
				<text class="value">{{ score.toString().padStart(6, '0') }}</text>
			</view>
			<view class="header-item">
				<text class="label">COINS</text>
				<view class="coins-value">
					<view class="coin-mini"></view>
					<text class="value">×{{ Math.floor(score / 10).toString().padStart(2, '0') }}</text>
				</view>
			</view>
			<view class="header-item">
				<text class="label">WORLD</text>
				<text class="value">1-1</text>
			</view>
			<view class="header-item">
				<text class="label">TOP</text>
				<text class="value">{{ highScore.toString().padStart(6, '0') }}</text>
			</view>
		</view>

		<view class="game-area" :style="{ width: areaSize + 'px', height: areaSize + 'px' }">
			<view class="snake-segment" 
				v-for="(segment, index) in snake" 
				:key="index"
				:class="{ 'snake-head': index === 0 }"
				:style="{ 
					left: segment.x * cellSize + 'px', 
					top: segment.y * cellSize + 'px', 
					width: cellSize + 'px', 
					height: cellSize + 'px',
					transition: `all ${gameSpeed}ms linear`
				}">
				<view class="inner-segment"></view>
			</view>
			
			<view class="food-container"
				:style="{ left: food.x * cellSize + 'px', top: food.y * cellSize + 'px', width: cellSize + 'px', height: cellSize + 'px' }">
				<view class="coin"></view>
			</view>
			
			<view v-if="isPaused" class="game-over-overlay">
				<text class="game-over-title">PAUSED</text>
				<button class="restart-btn pixel-btn" @click="onButtonBEnd">RESUME</button>
			</view>
			
			<view v-if="gameOver" class="game-over-overlay">
				<text class="game-over-title">GAME OVER</text>
				<button class="restart-btn pixel-btn" @click="startGame">TRY AGAIN</button>
			</view>
			
			<view v-if="!isPlaying && !gameOver" class="start-overlay">
				<text class="game-title">SUPER SNAKE</text>
				<button class="start-btn pixel-btn" @click="startGame">START</button>
				<view class="help-btn" @click="showHelp = true">?</view>
			</view>
			
			<view v-if="showHelp" class="help-overlay" @click="showHelp = false">
				<view class="help-box" @click.stop>
					<text class="help-title">HOW TO PLAY</text>
					<view class="help-content">
						<text class="help-item">🎮 Use D-PAD to move</text>
						<text class="help-item">🅰️ Hold A to speed up</text>
						<text class="help-item">🅱️ Press B to pause</text>
						<text class="help-item">🪙 Collect coins for points</text>
					</view>
					<button class="close-btn pixel-btn" @click="showHelp = false">OK</button>
				</view>
			</view>
		</view>

		<view class="controls-area">
			<view class="joystick-container-nes">
				<view class="joystick-base-nes"></view>
				<view class="joystick-cross" id="joystick"
					@touchstart="onJoystickStart" 
					@touchmove.stop.prevent="onJoystickMove" 
					@touchend="onJoystickEnd"
					@touchcancel="onJoystickEnd">
					<view class="d-pad-up"></view>
					<view class="d-pad-right"></view>
					<view class="d-pad-down"></view>
					<view class="d-pad-left"></view>
					<view class="d-pad-center" 
						:style="{ transform: `translate(${joystick.x * 0.5}px, ${joystick.y * 0.5}px)` }">
						<view class="d-pad-circle"></view>
					</view>
				</view>
			</view>
			<view class="action-buttons-nes">
