					@touchstart="onButtonBStart" 
					@touchend="onButtonBEnd"
					:class="{ 'btn-active': isPaused }">
				</view>
				<view class="action-btn-a" 
					@touchstart="onButtonAStart" 
					@touchend="onButtonAEnd"
					:class="{ 'btn-active': isAccelerating }">
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	export default {
		data() {
			return {
				score: 0,
				highScore: 0,
				cellSize: 20,
				gridSize: 15, // 15x15 grid
				snake: [{x: 5, y: 5}],
				food: {x: 10, y: 10},
				direction: 'RIGHT',
				nextDirection: 'RIGHT',
				gameLoop: null,
				isPlaying: false,
				gameOver: false,
				areaSize: 300, // cellSize * gridSize
				gameSpeed: 200,
				baseSpeed: 200,
				isAccelerating: false,
				isPaused: false,
				showHelp: false,
				
				// Joystick data
				joystick: {
					x: 0,
					y: 0,
					active: false,
					radius: 40, // Max movement radius
					centerX: 0,
					centerY: 0
				}
			}
		},
		onLoad() {
			this.areaSize = this.cellSize * this.gridSize;
			const savedHighScore = uni.getStorageSync('snake_high_score');
			if (savedHighScore) {
				this.highScore = savedHighScore;
			}
		},
		onReady() {
			this.initJoystick();
		},
		onUnload() {
			this.stopGame();
		},
		methods: {
			initJoystick() {
				const query = uni.createSelectorQuery().in(this);
				query.select('#joystick').boundingClientRect(data => {
					if (data) {
						this.joystick.centerX = data.left + data.width / 2;
						this.joystick.centerY = data.top + data.height / 2;
					}
				}).exec();
			},
			startGame() {
				this.score = 0;
				this.gameSpeed = 200;
				this.baseSpeed = 200;
				this.isAccelerating = false;
				this.isPaused = false;
				this.snake = [{x: 5, y: 5}, {x: 4, y: 5}, {x: 3, y: 5}];
				this.direction = 'RIGHT';
				this.nextDirection = 'RIGHT';
				this.gameOver = false;
				this.isPlaying = true;
				this.spawnFood();
				
				this.setGameTimer(this.gameSpeed);
			},
			setGameTimer(speed) {
				if (this.gameLoop) clearInterval(this.gameLoop);
				this.gameLoop = setInterval(this.gameTick, speed);
			},
			stopGame() {
				if (this.gameLoop) {
					clearInterval(this.gameLoop);
					this.gameLoop = null;
				}
				this.isPlaying = false;
			},
			gameTick() {
				this.direction = this.nextDirection;
				const head = {...this.snake[0]};

				switch (this.direction) {
					case 'UP': head.y--; break;
					case 'DOWN': head.y++; break;
					case 'LEFT': head.x--; break;
					case 'RIGHT': head.x++; break;
				}

				// Collision detection
				if (this.checkCollision(head)) {
					this.handleGameOver();
					return;
				}

				this.snake.unshift(head);

				// Eat food
				if (head.x === this.food.x && head.y === this.food.y) {
					this.score += 10;
					this.spawnFood();
					// Increase speed
					if (this.score % 50 === 0 && this.baseSpeed > 50) {
						this.baseSpeed -= 10;
						if (!this.isAccelerating) {
							this.gameSpeed = this.baseSpeed;
							this.setGameTimer(this.gameSpeed);
						}
					}
				} else {
					this.snake.pop();
				}
			},
			checkCollision(head) {
				// Wall collision
				if (head.x < 0 || head.x >= this.gridSize || head.y < 0 || head.y >= this.gridSize) {
					return true;
				}
				
				// Self collision
				// If head hits food, tail stays (grow). Check all segments.
				// If head doesn't hit food, tail moves. Check all except last.
				const isFood = (head.x === this.food.x && head.y === this.food.y);
				const limit = isFood ? this.snake.length : this.snake.length - 1;
				
				for (let i = 0; i < limit; i++) {
					if (head.x === this.snake[i].x && head.y === this.snake[i].y) {
						return true;
					}
				}
				return false;
			},
			spawnFood() {
				let valid = false;
				let newFood = {};
				while (!valid) {
					newFood = {
						x: Math.floor(Math.random() * this.gridSize),
						y: Math.floor(Math.random() * this.gridSize)
					};
					valid = !this.snake.some(segment => segment.x === newFood.x && segment.y === newFood.y);
				}
				this.food = newFood;
			},
			handleGameOver() {
				this.stopGame();
				this.gameOver = true;
				if (this.score > this.highScore) {
					this.highScore = this.score;
					uni.setStorageSync('snake_high_score', this.highScore);
				}
				uni.showToast({
					title: '游戏结束!',
					icon: 'none'
				});
			},
			changeDirection(dir) {
				// Prevent reversing direction directly
				const opposites = { 'UP': 'DOWN', 'DOWN': 'UP', 'LEFT': 'RIGHT', 'RIGHT': 'LEFT' };
				if (this.direction !== opposites[dir]) {
					this.nextDirection = dir;
				}
			},
			onJoystickStart(e) {
				if (!this.isPlaying) return;
				this.joystick.active = true;
				// Optional: Refresh center if needed, but keeping it simple
				this.updateJoystickPosition(e.touches[0]);
			},
			onJoystickMove(e) {
				if (!this.joystick.active) return;
				this.updateJoystickPosition(e.touches[0]);
			},
			onJoystickEnd(e) {
				this.joystick.active = false;
				this.joystick.x = 0;
				this.joystick.y = 0;
			},
			updateJoystickPosition(touch) {
				const dx = touch.clientX - this.joystick.centerX;
				const dy = touch.clientY - this.joystick.centerY;
				const distance = Math.sqrt(dx * dx + dy * dy);
				const angle = Math.atan2(dy, dx);
				
				const maxDist = this.joystick.radius;
				const clampedDist = Math.min(distance, maxDist);
				
				this.joystick.x = clampedDist * Math.cos(angle);
				this.joystick.y = clampedDist * Math.sin(angle);
				
				// Direction logic with deadzone
				if (distance > 10) { 
					if (Math.abs(dx) > Math.abs(dy)) {
						this.changeDirection(dx > 0 ? 'RIGHT' : 'LEFT');
					} else {
						this.changeDirection(dy > 0 ? 'DOWN' : 'UP');
					}
				}
			},
			onButtonAStart() {
				if (!this.isPlaying || this.isPaused || this.gameOver) return;
				this.isAccelerating = true;
				this.gameSpeed = this.baseSpeed / 2; // Double speed
				this.setGameTimer(this.gameSpeed);
			},
			onButtonAEnd() {
				if (!this.isPlaying || this.isPaused || this.gameOver) return;
				this.isAccelerating = false;
				this.gameSpeed = this.baseSpeed;
				this.setGameTimer(this.gameSpeed);
			},
			onButtonBStart() {
				// Use start/end pattern or just click. Touchstart is more responsive.
			},
			onButtonBEnd() {
				if (this.gameOver) {
					this.startGame();
					return;
				}
				
				if (!this.isPlaying && !this.gameOver) {
					this.startGame();
					return;
				}
				
				// Toggle Pause
				if (this.isPaused) {
					this.isPaused = false;
					this.setGameTimer(this.gameSpeed);
				} else {
					this.isPaused = true;
					clearInterval(this.gameLoop);
					this.gameLoop = null;
				}
			}
		}
	}
</script>

